   126→    detected: true,
   127→    detectionMethod:
   128→      attr.detectionMethod === 'pattern' || attr.detectionMethod === 'domainLookup' ? 'direct' : 'derived',
   129→    sourceField: attr.detectionMethod === 'pattern' ? 'emailBodyOrSubject' : undefined,
   130→    derivationLogic:
   131→      attr.detectionMethod === 'derived' || attr.detectionMethod === 'domainLookup'
   132→        ? attr.detectionEvidence
   133→        : undefined,
   134→    confidence: attr.confidence,
