     1→/**
     2→ * Attribute Detection Stage
     3→ *
     4→ * Stage 4 of the EmailCategorizer pipeline. Detects and derives contextual attributes
     5→ * from email content and metadata that will influence category scoring in the next stage.
     6→ *
     7→ * Implements pattern-based and derived attribute detection per SCORING_LOGIC.md
     8→ * "Attribute Detectors & Derived Attributes" section.
     9→ */
    10→
    11→import { EmailMessage, AttributeDetector, DerivedAttribute } from '../types';
    12→import { ClassificationSession } from '../types/classification-session';
    13→import { ClassificationResult } from '../types/classification-result';
    14→import { extractEmailBodyText } from '../utils/email-utils';
    15→
    16→/**
    17→ * Individual detected attribute result
    18→ */
    19→export interface DetectedAttribute {
    20→  attributeName: string;
    21→  attributeValue: boolean | string | number;
    22→  detectionMethod: 'pattern' | 'derived' | 'domainLookup';
    23→  detectionEvidence: string;
    24→  confidence: number;
    25→}
    26→
    27→/**
    28→ * Result of attribute detection stage
    29→ */
    30→export interface AttributeDetectionResult {
    31→  detectedAttributes: DetectedAttribute[];
    32→  processingDurationMs: number;
    33→  parallelProcessed: boolean;
    34→  dependencies: string[];
    35→  // Preserve previous stage data
    36→  [key: string]: unknown;
    37→}
    38→
    39→/**
    40→ * Attribute Detection Stage Configuration
    41→ */
    42→export interface AttributeDetectionStageConfig {
    43→  settings: {
    44→    attributeProcessing: {
    45→      detectSelfSent: boolean;
    46→      resolveDomains: boolean;
    47→      deriveContextFlags: boolean;
    48→    };
    49→  };
    50→  attributes: {
    51→    schema: Record<string, unknown>;
    52→    detectors: AttributeDetector[];
    53→    derived: Record<string, DerivedAttribute>;
    54→    attributeBonusMap?: Record<string, Record<string, number>>;
    55→  };
    56→  performanceCache?: {
    57→    financialDomains?: string[];
    58→    newsletterDomains?: string[];
    59→    logisticsDomains?: string[];
    60→  };
    61→}
    62→
    63→/**
    64→ * Execute attribute detection stage function (canonical signature)
    65→ *
    66→ * Mutates the result object in place by populating attributeContext.detectedAttributes
    67→ * and updating session performance metrics.
    68→ */
    69→export function executeAttributeDetection(
    70→  email: EmailMessage,
    71→  session: ClassificationSession,
    72→  result: ClassificationResult,
    73→  config: AttributeDetectionStageConfig
    74→): void {
    75→  const startTime = Date.now();
    76→
    77→  const detectedAttributes: DetectedAttribute[] = [];
    78→
    79→  // Apply pattern-based detectors
    80→  const patternAttributes = detectPatternAttributes(email, config);
    81→  detectedAttributes.push(...patternAttributes);
    82→
    83→  // Apply derived attribute logic
    84→  const derivedAttributes = detectDerivedAttributes(email, config);
    85→  detectedAttributes.push(...derivedAttributes);
    86→
    87→  // Detect urgency level and update result
    88→  const urgencyLevel = detectUrgency(email);
    89→  if (urgencyLevel !== 'none') {
    90→    // Only update if different from default 'none'
    91→    result.attributeContext.urgency = urgencyLevel;
    92→  }
    93→
    94→  // Mutate result: Update attribute context with detected attributes
    95→  for (const attr of detectedAttributes) {
    96→    result.attributeContext.detectionMetadata[attr.attributeName] = {
    97→      confidence: attr.confidence,
    98→      detectionMethod: attr.detectionMethod,
    99→      evidence: attr.detectionEvidence,
   100→      detectedAt: new Date(),
   101→    };
   102→  }
   103→
   104→  // Track performance in session
   105→  const duration = Date.now() - startTime;
   106→  if (!session.performanceMetrics) {
   107→    session.performanceMetrics = {
   108→      totalDurationMs: 0,
   109→      avgEmailDurationMs: 0,
   110→      parallelStagesCount: 0,
   111→      databaseBatchOps: 0,
   112→    };
   113→  }
   114→  session.performanceMetrics.parallelStagesCount += 1;
   115→
   116→  // Update result processing duration
   117→  result.processingDurationMs += duration;
   118→
   119→  // Add parallel stage result tracking
   120→  result.parallelStageResults.push({
   121→    stageId: `attribute_detection_${result.id}`,
   122→    stageName: 'attributeDetection',
   123→    executionTimeMs: duration,
   124→    parallelWithStages: [], // This stage can run in parallel
   125→    dependentOnStages: ['ruleScoring'], // Depends on earlier stages
   126→    cacheHitsCount: 0,
   127→    errorCount: 0,
   128→  });
   129→
   130→  // Update explainability trace (convert to ExplainabilityTrace.AttributeDetectionResult format)
   131→  result.explainabilityTrace.attributeDetection = detectedAttributes.map((attr) => ({
   132→    attribute: attr.attributeName,
   133→    detected: true,
   134→    detectionMethod:
   135→      attr.detectionMethod === 'pattern' || attr.detectionMethod === 'domainLookup' ? 'direct' : 'derived',
   136→    sourceField: attr.detectionMethod === 'pattern' ? 'emailBodyOrSubject' : undefined,
   137→    derivationLogic:
   138→      attr.detectionMethod === 'derived' || attr.detectionMethod === 'domainLookup'
   139→        ? attr.detectionEvidence
   140→        : undefined,
   141→    confidence: attr.confidence,
   142→    parallelProcessed: true,
   143→    dependencies: [],
   144→    reason: attr.detectionEvidence,
   145→  }));
   146→
   147→  result.explainabilityTrace.stageTimings['attributeDetection'] = duration;
   148→  result.explainabilityTrace.configurationRefs['attributeDetection'] = 'attributes.detectors';
   149→}
   150→
   151→/**
   152→ * Detect pattern-based attributes using configured detectors
   153→ */
   154→function detectPatternAttributes(email: EmailMessage, config: AttributeDetectionStageConfig): DetectedAttribute[] {
   155→  const detectors = config.attributes?.detectors || [];
   156→  const detectedAttributes: DetectedAttribute[] = [];
   157→
   158→  for (const detector of detectors) {
   159→    try {
   160→      const detection = applyDetector(email, detector);
   161→      if (detection.detected) {
   162→        detectedAttributes.push({
   163→          attributeName: detector.attribute,
   164→          attributeValue: detection.value as string | number | boolean,
   165→          detectionMethod: 'pattern',
   166→          detectionEvidence: detection.evidence || 'Pattern match',
   167→          confidence: 0.8, // Default confidence for pattern matches
   168→        });
   169→      }
   170→    } catch (error) {
   171→      // Log error but continue processing
   172→      console.warn(`Error applying detector for ${detector.attribute}:`, error);
   173→    }
   174→  }
   175→
   176→  return detectedAttributes;
   177→}
   178→
   179→/**
   180→ * Apply individual detector pattern to email content
   181→ */
   182→function applyDetector(
   183→  email: EmailMessage,
   184→  detector: AttributeDetector
   185→): { detected: boolean; value?: unknown; evidence?: string } {
   186→  const { field, operation, values } = detector;
   187→
   188→  // Get the field content to search
   189→  let searchContent = '';
   190→  switch (field) {
   191→    case 'body':
   192→      searchContent = extractEmailBodyText(email);
   193→      break;
   194→    case 'subject':
   195→      searchContent = email.subject || '';
   196→      break;
   197→    case 'from.address':
   198→      searchContent = email.from?.email || '';
   199→      break;
   200→    case 'from.name':
   201→      searchContent = email.from?.name || '';
   202→      break;
   203→    default:
   204→      console.warn(`Unknown field type for detector: ${field}`);
   205→      return { detected: false };
   206→  }
   207→
   208→  // Apply detection operation
   209→  switch (operation) {
   210→    case 'containsAny':
   211→      for (const value of values) {
   212→        if (searchContent.toLowerCase().includes(value.toLowerCase())) {
   213→          return {
   214→            detected: true,
   215→            value: true,
   216→            evidence: `Found "${value}" in ${field}`,
   217→          };
   218→        }
   219→      }
   220→      break;
   221→
   222→    case 'regexAny':
   223→      for (const pattern of values) {
   224→        try {
   225→          const regex = new RegExp(pattern, 'ig'); // Add global flag for better matching
   226→          const match = searchContent.match(regex);
   227→          if (match) {
   228→            // For amount patterns, try to match the longest currency pattern
   229→            let bestMatch = match[0];
   230→            if (pattern.includes('\\$\\d+')) {
   231→              // Special handling for currency amounts - match full amounts with decimals
   232→              const fullAmountRegex = /\$\d+(?:\.\d{2})?/g;
   233→              const fullMatches = searchContent.match(fullAmountRegex);
   234→              if (fullMatches && fullMatches.length > 0) {
   235→                bestMatch = fullMatches[0]; // Use the first full amount match
   236→              }
   237→            }
   238→            return {
   239→              detected: true,
   240→              value: true,
   241→              evidence: `Regex "${pattern}" matched: "${bestMatch}" in ${field}`,
   242→            };
   243→          }
   244→        } catch (error) {
   245→          console.warn(`Invalid regex pattern: ${pattern}`, error);
   246→          continue;
   247→        }
   248→      }
   249→      break;
   250→
   251→    case 'startsWith':
   252→      for (const value of values) {
   253→        if (searchContent.toLowerCase().startsWith(value.toLowerCase())) {
   254→          return {
   255→            detected: true,
   256→            value: true,
   257→            evidence: `${field} starts with "${value}"`,
   258→          };
   259→        }
   260→      }
   261→      break;
   262→
   263→    case 'endsWith':
   264→      for (const value of values) {
   265→        if (searchContent.toLowerCase().endsWith(value.toLowerCase())) {
   266→          return {
   267→            detected: true,
   268→            value: true,
   269→            evidence: `${field} ends with "${value}"`,
   270→          };
   271→        }
   272→      }
   273→      break;
   274→
   275→    default:
   276→      console.warn(`Unknown operation type: ${operation}`);
   277→  }
   278→
   279→  return { detected: false };
   280→}
   281→
   282→/**
   283→ * Detect derived attributes using logical rules
   284→ */
   285→function detectDerivedAttributes(email: EmailMessage, config: AttributeDetectionStageConfig): DetectedAttribute[] {
   286→  const settings = config.settings?.attributeProcessing;
   287→  const detectedAttributes: DetectedAttribute[] = [];
   288→
   289→  // Derive selfSent attribute (if enabled, default true)
   290→  const detectSelfSent = !settings || settings.detectSelfSent !== false;
   291→  if (detectSelfSent) {
   292→    const selfSent = deriveSelfSent(email);
   293→    if (selfSent) {
   294→      detectedAttributes.push(selfSent);
   295→    }
   296→  }
   297→
   298→  // Domain-based derivations (if enabled, default true)
   299→  const resolveDomains = !settings || settings.resolveDomains !== false;
   300→  if (resolveDomains) {
   301→    // Derive fromFinancialInstitution attribute
   302→    const financialInstitution = deriveFromFinancialInstitution(email, config);
   303→    if (financialInstitution) {
   304→      detectedAttributes.push(financialInstitution);
   305→    }
   306→
   307→    // Derive fromNewsletterSource attribute
   308→    const newsletterSource = deriveFromNewsletterSource(email, config);
   309→    if (newsletterSource) {
   310→      detectedAttributes.push(newsletterSource);
   311→    }
   312→
   313→    // Derive fromLogisticsCarrier attribute
   314→    const logisticsCarrier = deriveFromLogisticsCarrier(email, config);
   315→    if (logisticsCarrier) {
   316→      detectedAttributes.push(logisticsCarrier);
   317→    }
   318→  }
   319→
   320→  // Gmail category derivations (always enabled - based on Gmail API labelIds)
   321→  const gmailCategories = deriveGmailCategories(email);
   322→  detectedAttributes.push(...gmailCategories);
   323→
   324→  return detectedAttributes;
   325→}
   326→
   327→/**
   328→ * Derive selfSent attribute - email sent from user to self
   329→ */
   330→function deriveSelfSent(email: EmailMessage): DetectedAttribute | null {
   331→  const userAddresses = getUserAddresses();
   332→  const fromAddress = email.from?.email?.toLowerCase();
   333→
   334→  // Check if from address is user address
   335→  if (!fromAddress || !userAddresses.includes(fromAddress)) {
   336→    return null;
   337→  }
   338→
   339→  // Check if all recipients are user addresses
   340→  const allRecipients: string[] = [];
   341→  if (email.to) {
   342→    allRecipients.push(...email.to.map((addr) => addr.email.toLowerCase()));
   343→  }
   344→  if (email.cc) {
   345→    allRecipients.push(...email.cc.map((addr) => addr.email.toLowerCase()));
   346→  }
   347→  if (email.bcc) {
   348→    allRecipients.push(...email.bcc.map((addr) => addr.email.toLowerCase()));
   349→  }
   350→
   351→  const allRecipientsAreUser = allRecipients.length > 0 && allRecipients.every((addr) => userAddresses.includes(addr));
   352→
   353→  // Check for List-Id header (exclude mailing lists)
   354→  const hasListId = email.payload?.headers?.some((header) => header.name.toLowerCase() === 'list-id');
   355→
   356→  if (allRecipientsAreUser && !hasListId) {
   357→    return {
   358→      attributeName: 'selfSent',
   359→      attributeValue: true,
   360→      detectionMethod: 'derived',
   361→      detectionEvidence: 'All recipients match user addresses',
   362→      confidence: 0.9,
   363→    };
   364→  }
   365→
   366→  return null;
   367→}
   368→
   369→/**
   370→ * Derive fromFinancialInstitution attribute using domain lookup
   371→ */
   372→function deriveFromFinancialInstitution(
   373→  email: EmailMessage,
   374→  config: AttributeDetectionStageConfig
   375→): DetectedAttribute | null {
   376→  const fromAddress = email.from?.email?.toLowerCase();
   377→  if (!fromAddress) return null;
   378→
   379→  const fromDomain = extractBaseDomain(fromAddress);
   380→  const financialDomains = getFinancialDomains(config);
   381→
