  describe('Urgency Detection', () => {
    test('should detect high urgency from X-Priority header 1', () => {
      const urgentEmailPriority1 = {
        ...mockEmailMessage,
        payload: {
          ...mockEmailMessage.payload,
          headers: [
            ...mockEmailMessage.payload.headers,
            { name: 'X-Priority', value: '1' },
          ],
        },
        subject: 'Regular subject',
        bodyPlain: 'Regular email content',
      };

      executeAttributeDetection(urgentEmailPriority1, session, result, stageConfig);

      expect(result.attributeContext.urgency).toBe('high');
    });

    test('should detect high urgency from X-Priority header 2', () => {
      const urgentEmailPriority2 = {
        ...mockEmailMessage,
        payload: {
          ...mockEmailMessage.payload,
          headers: [
            ...mockEmailMessage.payload.headers,
            { name: 'X-Priority', value: '2' },
          ],
        },
        subject: 'Regular subject',
        bodyPlain: 'Regular email content',
      };

      executeAttributeDetection(urgentEmailPriority2, session, result, stageConfig);

      expect(result.attributeContext.urgency).toBe('high');
    });

    test('should detect high urgency from "urgent" keyword in subject', () => {
      const urgentEmailKeyword = {
        ...mockEmailMessage,
        subject: 'Urgent: Payment Required',
        bodyPlain: 'Please process payment',
      };

      executeAttributeDetection(urgentEmailKeyword, session, result, stageConfig);

      expect(result.attributeContext.urgency).toBe('high');
    });

    test('should detect high urgency from "immediately" keyword in body', () => {
      const urgentEmailImmediately = {
        ...mockEmailMessage,
        subject: 'Payment Reminder',
        bodyPlain: 'Please respond immediately to this request',
      };

      executeAttributeDetection(urgentEmailImmediately, session, result, stageConfig);

      expect(result.attributeContext.urgency).toBe('high');
    });

    test('should detect high urgency from "asap" keyword', () => {
      const urgentEmailAsap = {
        ...mockEmailMessage,
        subject: 'Need this ASAP',
        bodyPlain: 'Could you review this document?',
      };

      executeAttributeDetection(urgentEmailAsap, session, result, stageConfig);

      expect(result.attributeContext.urgency).toBe('high');
    });

    test('should detect high urgency from "critical" keyword', () => {
      const urgentEmailCritical = {
        ...mockEmailMessage,
        subject: 'System Issue',
        bodyPlain: 'This is a critical system error that needs attention',
      };

      executeAttributeDetection(urgentEmailCritical, session, result, stageConfig);

      expect(result.attributeContext.urgency).toBe('high');
    });

    test('should detect high urgency from "emergency" keyword', () => {
      const urgentEmailEmergency = {
        ...mockEmailMessage,
        subject: 'Emergency Maintenance',
        bodyPlain: 'Emergency maintenance required',
      };

      executeAttributeDetection(urgentEmailEmergency, session, result, stageConfig);

      expect(result.attributeContext.urgency).toBe('high');
    });

    test('should detect high urgency from "action required" keyword', () => {
      const urgentEmailAction = {
