            { name: 'X-Priority', value: '3' },
          ],
        },
        subject: 'Regular subject',
        bodyPlain: 'Regular email content',
      };

      executeAttributeDetection(mediumUrgencyPriority3, session, result, stageConfig);

      expect(result.attributeContext.urgency).toBe('medium');
    });

    test('should detect medium urgency from "soon" keyword in body', () => {
      const mediumUrgencySoon = {
        ...mockEmailMessage,
        subject: 'Meeting Reminder',
        bodyPlain: 'Please respond soon to confirm attendance',
      };

      executeAttributeDetection(mediumUrgencySoon, session, result, stageConfig);

      expect(result.attributeContext.urgency).toBe('medium');
    });

    test('should detect medium urgency from "important" keyword', () => {
      const mediumUrgencyImportant = {
        ...mockEmailMessage,
        subject: 'Important: Policy Update',
        bodyPlain: 'Please review this policy change',
      };

      executeAttributeDetection(mediumUrgencyImportant, session, result, stageConfig);

      expect(result.attributeContext.urgency).toBe('medium');
    });

    test('should detect medium urgency from "please review" keyword', () => {
      const mediumUrgencyReview = {
        ...mockEmailMessage,
        subject: 'Document Review',
        bodyPlain: 'Please review the attached document at your convenience',
      };

      executeAttributeDetection(mediumUrgencyReview, session, result, stageConfig);

      expect(result.attributeContext.urgency).toBe('medium');
    });

    test('should detect low urgency from X-Priority header 4', () => {
      const lowUrgencyPriority4 = {
        ...mockEmailMessage,
        payload: {
          ...mockEmailMessage.payload,
          headers: [
            ...mockEmailMessage.payload.headers,
            { name: 'X-Priority', value: '4' },
          ],
        },
        subject: 'Newsletter',
        bodyPlain: 'Weekly updates',
      };

      executeAttributeDetection(lowUrgencyPriority4, session, result, stageConfig);

      expect(result.attributeContext.urgency).toBe('low');
    });

    test('should detect low urgency from X-Priority header 5', () => {
      const lowUrgencyPriority5 = {
        ...mockEmailMessage,
        payload: {
          ...mockEmailMessage.payload,
          headers: [
            ...mockEmailMessage.payload.headers,
            { name: 'X-Priority', value: '5' },
          ],
        },
        subject: 'Newsletter',
        bodyPlain: 'Weekly updates',
      };

      executeAttributeDetection(lowUrgencyPriority5, session, result, stageConfig);

      expect(result.attributeContext.urgency).toBe('low');
    });

    test('should detect low urgency from "fyi" keyword', () => {
      const lowUrgencyFyi = {
        ...mockEmailMessage,
        subject: 'FYI: Team Update',
        bodyPlain: 'Just wanted to keep you in the loop',
      };

      executeAttributeDetection(lowUrgencyFyi, session, result, stageConfig);

      expect(result.attributeContext.urgency).toBe('low');
    });

    test('should detect low urgency from "no rush" keyword', () => {
      const lowUrgencyNoRush = {
        ...mockEmailMessage,
        subject: 'Document Sharing',
        bodyPlain: 'Here are the docs. No rush to review them.',
      };

      executeAttributeDetection(lowUrgencyNoRush, session, result, stageConfig);

      expect(result.attributeContext.urgency).toBe('low');
    });

    test('should default to none when no urgency indicators present', () => {
      const noUrgencyEmail = {
        ...mockEmailMessage,
        subject: 'Weekly Newsletter',
        bodyPlain: 'Here is your weekly summary of articles',
      };

      executeAttributeDetection(noUrgencyEmail, session, result, stageConfig);

      expect(result.attributeContext.urgency).toBe('none');
    });

    test('should handle missing X-Priority header gracefully', () => {
      const emailNoHeader = {
        ...mockEmailMessage,
        payload: {
          ...mockEmailMessage.payload,
          headers: mockEmailMessage.payload.headers.filter((h) => h.name !== 'X-Priority'),
        },
        subject: 'Test Email',
        bodyPlain: 'Regular content',
      };

      executeAttributeDetection(emailNoHeader, session, result, stageConfig);

      expect(result.attributeContext.urgency).toBe('none');
    });

    test('should handle empty email content', () => {
      const emailEmpty = {
        ...mockEmailMessage,
        subject: '',
        bodyPlain: '',
      };

      executeAttributeDetection(emailEmpty, session, result, stageConfig);

      expect(result.attributeContext.urgency).toBe('none');
    });

    test('should prioritize X-Priority header over keywords', () => {
      const emailPriorityWins = {
        ...mockEmailMessage,
        payload: {
          ...mockEmailMessage.payload,
          headers: [
            ...mockEmailMessage.payload.headers,
            { name: 'X-Priority', value: '1' }, // High priority header
          ],
        },
        subject: 'FYI: Update', // Low urgency keyword
        bodyPlain: 'No rush to review this', // Low urgency keyword
      };

      executeAttributeDetection(emailPriorityWins, session, result, stageConfig);

      // X-Priority: 1 should override low urgency keywords
      expect(result.attributeContext.urgency).toBe('high');
    });

    test('should be case insensitive for keyword detection', () => {
      const emailMixedCase = {
        ...mockEmailMessage,
        subject: 'URGENT: System Alert',
        bodyPlain: 'Please RESPOND IMMEDIATELY to this CRITICAL issue',
      };

      executeAttributeDetection(emailMixedCase, session, result, stageConfig);

      expect(result.attributeContext.urgency).toBe('high');
    });

    test('should handle malformed X-Priority header', () => {
      const emailBadPriority = {
        ...mockEmailMessage,
        payload: {
          ...mockEmailMessage.payload,
          headers: [
            ...mockEmailMessage.payload.headers,
            { name: 'X-Priority', value: 'not-a-number' },
          ],
        },
        subject: 'Test Email',
        bodyPlain: 'Regular content',
      };

      executeAttributeDetection(emailBadPriority, session, result, stageConfig);

      // Should default to 'none' when X-Priority is malformed
      expect(result.attributeContext.urgency).toBe('none');
    });

    test('should detect high urgency with multiple high urgency keywords', () => {
      const emailMultipleHighKeywords = {
        ...mockEmailMessage,
        subject: 'URGENT and CRITICAL: Action Required',
        bodyPlain: 'This is an emergency that needs immediate attention ASAP',
      };

      executeAttributeDetection(emailMultipleHighKeywords, session, result, stageConfig);

      expect(result.attributeContext.urgency).toBe('high');
    });

    test('should detect high urgency when keyword is in middle of sentence', () => {
      const emailMidSentence = {
        ...mockEmailMessage,
        subject: 'System Status',
        bodyPlain: 'We have detected a critical error in the payment system',
      };

      executeAttributeDetection(emailMidSentence, session, result, stageConfig);

      expect(result.attributeContext.urgency).toBe('high');
    });
  });
});

